181	/// Skip noise elements that are too generic to produce meaningful diff entries.
182	fn skip_noise_element(el: &ans_core::distill::DistilledElement) -> bool {
183	    // Skip empty text-less elements that appear and disappear with layout shifts
184	    el.text.trim().is_empty()
185	        && !["button", "input", "select", "textarea", "a"].contains(&el.tag.as_str())
186	}
187	
188	/// Truncate text for diff display.
189	fn truncate_for_diff(text: &str) -> String {
190	    // Safe truncation — slice at char boundary, not raw byte offset
191	    if text.len() > 100 {
192	        let truncate_at = text
193	            .char_indices()
194	            .take_while(|&(i, _)| i < 100)
195	            .map(|(i, c)| i + c.len_utf8())
196	            .last()
197	            .unwrap_or(100);
198	        format!("{}...", &text[..truncate_at.min(text.len())])
199	    } else {
200	        text.to_string()
201	    }
202	}
203	
204	/// Detect distractions that appeared in the new page but not the old.
205	fn detect_new_distractions(before: &DistilledPage, after: &DistilledPage) -> Vec<ElementChange> {
206	    let before_has_ads = before
207	        .semantic_blocks
208	        .iter()
209	        .any(|b| matches!(b.block_type, ans_core::distill::BlockType::Ad));
210	    let after_has_ads = after
211	        .semantic_blocks
212	        .iter()
213	        .any(|b| matches!(b.block_type, ans_core::distill::BlockType::Ad));
214	
215	    if !before_has_ads && after_has_ads {
216	        // Find ad blocks in after
217	        after
218	            .semantic_blocks
219	            .iter()
220	            .filter(|b| matches!(b.block_type, ans_core::distill::BlockType::Ad))
221	            .filter_map(|b| {
222	                b.element_indices.first().and_then(|&i| {
223	                    after.elements.get(i).map(|el| ElementChange {
224	                        tag: el.tag.clone(),
225	                        text: "Ad detected".into(),
226	                        selector: crate::types::element_selector(el),
227	                        index: i as i32,
228	                    })
229	                })
230	            })
231	            .collect()
232	    } else {
233	        vec![]
234	    }
235	}
