237	/// Classify the overall change type from the diff details.
238	fn classify_change(
239	    added: &[ElementChange],
240	    removed: &[ElementChange],
241	    modified: &[ElementModification],
242	    _before: &DistilledPage,
243	    after: &DistilledPage,
244	) -> String {
245	    let total_changes = added.len() + removed.len() + modified.len();
246	
247	    if total_changes == 0 {
248	        return "no_change".into();
249	    }
250	
251	    // Check for error states
252	    let after_text: String = after
253	        .elements
254	        .iter()
255	        .map(|el| el.text.as_str())
256	        .collect::<Vec<_>>()
257	        .join(" ");
258	    let after_lower = after_text.to_lowercase();
259	
260	    let error_patterns = [
261	        "error",
262	        "not found",
263	        "404",
264	        "500",
265	        "access denied",
266	        "forbidden",
267	    ];
268	    if error_patterns.iter().any(|p| after_lower.contains(p)) {
269	        return "error_state".into();
270	    }
271	
272	    // Check for distraction appearance
273	    let distraction_added = added.iter().any(|c| {
274	        c.text.contains("Ad detected") || c.text.contains("cookie") || c.text.contains("popup")
275	    });
276	    if distraction_added {
277	        return "distraction_appeared".into();
278	    }
279	
280	    // Check for form updates
281	    let form_tags = ["input", "select", "textarea", "button", "form"];
282	    let has_form_change = added.iter().any(|c| form_tags.contains(&c.tag.as_str()))
283	        || removed.iter().any(|c| form_tags.contains(&c.tag.as_str()))
284	        || modified.iter().any(|m| {
285	            ["value", "checked", "selected", "disabled"].contains(&m.attribute_name.as_str())
286	        });
287	
288	    if has_form_change {
289	        return "form_update".into();
290	    }
291	
292	    // Check if only cosmetic changes (style, class)
293	    let only_cosmetic = modified.iter().all(|m| {
294	        ["style", "class", "data-"]
295	            .iter()
296	            .any(|p| m.attribute_name.starts_with(p))
297	    }) && added.is_empty()
298	        && removed.is_empty();
299	
300	    if only_cosmetic {
301	        return "cosmetic_change".into();
302	    }
303	
304	    // Check for content text changes
305	    let has_text_change = modified.iter().any(|m| m.attribute_name == "text");
306	    if has_text_change {
307	        return "content_update".into();
308	    }
309	
310	    // Default
311	    "content_update".into()
312	}
